// ── Config ──────────────────────────────────────────────────────────────────
// Set your Mercanta business_account_id from Supabase here:
const BUSINESS_ACCOUNT_ID = 'YOUR-BUSINESS-ACCOUNT-UUID-HERE';

// Admin phones (91-prefixed, no spaces):
const ADMIN_PHONES = ['916005499183'];

// Franchise owner phones:
const FRANCHISE_PHONES = ['91XXXXXXXXXX', '91XXXXXXXXXX'];

// ── Parse incoming Evolution API webhook payload ─────────────────────────────
const body = $input.item.json.body || $input.item.json;
const messageData = body?.data || body;

// Extract sender phone and message text
let sender = '';
let msgText = '';
let msgType = '';

try {
  sender = (messageData?.key?.remoteJid || '').replace('@s.whatsapp.net','').replace('@g.us','');
  msgType = messageData?.message ? Object.keys(messageData.message)[0] : '';
  if (msgType === 'conversation') {
    msgText = messageData.message.conversation || '';
  } else if (msgType === 'extendedTextMessage') {
    msgText = messageData.message.extendedTextMessage?.text || '';
  } else {
    msgText = '';
  }
} catch(e) {
  sender = '';
  msgText = '';
}

msgText = msgText.trim();
const msgLower = msgText.toLowerCase();

// ── Detect role ──────────────────────────────────────────────────────────────
let role = 'customer'; // default
if (ADMIN_PHONES.includes(sender)) role = 'admin';
else if (FRANCHISE_PHONES.includes(sender)) role = 'franchise';

// ── Parse command ────────────────────────────────────────────────────────────
// Commands the bot understands:
// Admin   : stock | addstock <item> <qty> | additem <category> <name> <price>
// Franchise: sales | stock <item>
// Customer : menu | buy <item> [qty] | receipt

const parts = msgText.split(/\s+/);
const cmd = (parts[0] || '').toLowerCase();
const arg1 = parts[1] || '';
const arg2 = parts[2] || '';
const arg3 = parts[3] || '';

// For buy command, item name may have multiple words — everything between cmd and last token
let itemName = '';
if (cmd === 'buy' && parts.length >= 2) {
  // Last arg might be a number (qty), rest is item name
  const lastArg = parts[parts.length - 1];
  const hasQty = /^\d+$/.test(lastArg) && parts.length > 2;
  itemName = hasQty ? parts.slice(1, -1).join(' ') : parts.slice(1).join(' ');
}
if (cmd === 'addstock') {
  // addstock <name possibly multi word> <qty>
  const lastArg = parts[parts.length - 1];
  itemName = /^\d+$/.test(lastArg) ? parts.slice(1, -1).join(' ') : parts.slice(1).join(' ');
}
if (cmd === 'stock' && role !== 'admin') {
  itemName = parts.slice(1).join(' ');
}

const qty = parseInt(arg1, 10) || 1;
const buyQty = (() => {
  if (cmd !== 'buy') return 1;
  const last = parseInt(parts[parts.length - 1], 10);
  return (parts.length > 2 && last > 0) ? last : 1;
})();

return [{
  json: {
    sender,
    role,
    cmd,
    arg1,
    arg2,
    arg3,
    itemName,
    buyQty,
    msgText,
    BUSINESS_ACCOUNT_ID
  }
}];

const rows = $input.all();
if (!rows || rows.length === 0) return [{ json: { reply: '⚠️ No menu items found.' } }];

let text = '📋 *Mercanta Stock Levels*\n\n';
let currentCat = '';
for (const r of rows) {
  const item = r.json;
  if (item.category !== currentCat) {
    currentCat = item.category;
    text += `*${currentCat}*\n`;
  }
  const status = item.is_available ? '✅' : '❌';
  const tags = [];
  if (item.is_vegetarian) tags.push('🌿Veg');
  if (item.is_spicy) tags.push('🌶️Spicy');
  text += `  ${status} ${item.item_name} — ₹${parseFloat(item.price).toFixed(2)} ${tags.join(' ')}\n`;
}
text += '\n_Reply: addstock <item> to mark available_\n_Reply: additem <cat> <name> <price> to add item_';
return [{ json: { reply: text } }];

const rows = $input.all();
if (!rows || rows.length === 0) return [{ json: { reply: '⚠️ Item not found. Check the item name and try again.' } }];
const item = rows[0].json;
return [{ json: { reply: `✅ *${item.item_name}* is now marked as *available*.` } }];

const data = $('Parse & Classify').item.json;
const category = data.arg1 || '';
const price = parseFloat(data.arg3) || 0;
// item name = everything between arg1 and arg3 in the original message
// 'additem <category> <name words> <price>'
const parts = data.msgText.split(/\s+/);
// parts[0]=additem, parts[1]=category, parts[-1]=price, middle = name
let itemName = '';
if (parts.length >= 4) {
  itemName = parts.slice(2, parts.length - 1).join(' ');
} else {
  itemName = data.arg2 || '';
}
return [{ json: { category, itemName, price, BUSINESS_ACCOUNT_ID: data.BUSINESS_ACCOUNT_ID } }];

const rows = $input.all();
if (!rows || rows.length === 0) return [{ json: { reply: '⚠️ Failed to add item. Check format: additem <category> <name> <price>' } }];
const item = rows[0].json;
return [{ json: { reply: `✅ *${item.item_name}* added to *${item.category}* at *₹${parseFloat(item.price).toFixed(2)}*.` } }];

const rows = $input.all();
if (!rows || rows.length === 0) return [{ json: { reply: '📭 No recent sales found.' } }];

// Group by sale date + customer
const grouped = {};
for (const r of rows) {
  const item = r.json;
  const dateStr = new Date(item.date).toLocaleDateString('en-IN', { day:'2-digit', month:'short', hour:'2-digit', minute:'2-digit', hour12:true });
  const key = `${dateStr} — ${item.customer_name}`;
  if (!grouped[key]) grouped[key] = { total: item.total, lines: [] };
  grouped[key].lines.push(`    ${item.item_name} ×${item.quantity} @ ₹${parseFloat(item.price).toFixed(2)}`);
}

const keys = Object.keys(grouped).slice(0, 5);
let text = '📊 *Last 5 Sales*\n\n';
for (const k of keys) {
  text += `*${k}*\n`;
  text += grouped[k].lines.join('\n') + '\n';
  text += `  💰 Total: ₹${parseFloat(grouped[k].total).toFixed(2)}\n\n`;
}
return [{ json: { reply: text.trim() } }];

const rows = $input.all();
if (!rows || rows.length === 0) return [{ json: { reply: '⚠️ Item not found. Send `stock <item name>` to check.' } }];
const item = rows[0].json;
const status = item.is_available ? '✅ Available' : '❌ Not available';
const desc = item.description ? `\n_${item.description}_` : '';
return [{ json: { reply: `🍽️ *${item.item_name}*${desc}\nCategory: ${item.category}\nPrice: ₹${parseFloat(item.price).toFixed(2)}\nStatus: ${status}` } }];

const rows = $input.all();
if (!rows || rows.length === 0) return [{ json: { reply: '😔 No items available right now. Check back soon!' } }];

let text = '🍽️ *Mercanta Menu*\n\n';
let currentCat = '';
for (const r of rows) {
  const item = r.json;
  if (item.category !== currentCat) {
    currentCat = item.category;
    text += `*${currentCat}*\n`;
  }
  const tags = [];
  if (item.is_vegetarian) tags.push('🌿');
  if (item.is_spicy) tags.push('🌶️');
  const tagStr = tags.length ? ` ${tags.join('')}` : '';
  text += `  • ${item.item_name}${tagStr} — ₹${parseFloat(item.price).toFixed(2)}\n`;
}
text += '\n_To order: `buy <item name>` or `buy <item name> <qty>`_';
return [{ json: { reply: text } }];

const rows = $input.all();
const classify = $('Parse & Classify').item.json;

if (!rows || rows.length === 0) {
  return [{ json: { found: false, reply: `⚠️ Sorry, *${classify.itemName}* is not available. Send *menu* to see what we have.` } }];
}

const item = rows[0].json;
const qty = classify.buyQty || 1;
const total = parseFloat(item.price) * qty;
const totalPaise = Math.round(total * 100); // Razorpay uses paise

return [{
  json: {
    found: true,
    itemId: item.id,
    itemName: item.item_name,
    price: parseFloat(item.price),
    qty,
    total,
    totalPaise,
    sender: classify.sender,
    BUSINESS_ACCOUNT_ID: classify.BUSINESS_ACCOUNT_ID
  }
}];

const order = $('Customer: Build Order').item.json;
const link = $('Razorpay: Create Payment Link').item.json;
const reply = `🛒 *Order Summary*

📦 ${order.qty}× ${order.itemName}
💰 Total: ₹${order.total.toFixed(2)}

💳 *Pay here:*
${link.short_url}

_Your order will be confirmed after payment. Send *receipt* to see your last order._`;
return [{ json: { reply } }];

const rows = $input.all();
if (!rows || rows.length === 0) return [{ json: { reply: '📭 No orders found yet.' } }];

const latest = rows[0].json;
const dateStr = new Date(latest.date).toLocaleString('en-IN', { timeZone: 'Asia/Kolkata', day:'2-digit', month:'short', year:'numeric', hour:'2-digit', minute:'2-digit', hour12: true });
const payDetails = latest.payment_details || {};
const payId = payDetails.razorpay_payment_id || payDetails.razorpay_payment_link_id || '—';
const status = payDetails.webhook_verified ? '✅ Verified' : (payDetails.status === 'pending' ? '⏳ Pending' : '✅ Paid');

let text = `🧾 *Your Last Order*\n📅 ${dateStr}\n\n`;
for (const r of rows) {
  const item = r.json;
  text += `  • ${item.item_name} ×${item.quantity} @ ₹${parseFloat(item.price).toFixed(2)}\n`;
}
text += `\n💰 *Total: ₹${parseFloat(latest.total).toFixed(2)}*\n`;
text += `📋 Status: ${status}\n`;
text += `🔑 Ref: ${payId}`;
return [{ json: { reply: text } }];
